// --- Watch Registration ---

// RegisterHalcmdWatch registers WebSocket watch functions and commands.
func RegisterHalcmdWatch(wreg *apiserver.WatchRegistry, instance string, watchImpl HalcmdWatchCallbacks, commands []apiserver.CommandMeta) {
	wreg.Register(&apiserver.WatchAPI{
		APIName:  "halcmd",
		Instance: instance,
		Watches: []apiserver.WatchFuncMeta{
			{Name: "watch_items", DefaultRate: 100 * time.Millisecond, Watch: func() (json.RawMessage, error) {
				result, err := watchImpl.WatchItems()
				if err != nil { return nil, err }
				return json.Marshal(result)
			}},
		},
		Commands: commands,
	})
}
